//   4. Alice's seats >= 2 * seats of every other coalition member
//   5. Coalition's total seats is a strict majority of all parliament seats
ghost predicate IsValidCoalition(n: int, a: seq<int>, coalition: seq<int>)
  requires |a| == n >= 1
